const TOTAL_PAGES = 23;
const pages = [];

for (let i = 1; i <= TOTAL_PAGES; i++) {
  pages.push({
    json: {
      page: i,
      token: TOKEN,
      totalPages: TOTAL_PAGES
    }
  });
}

return pages;

// Processar os resultados de cada página
const data = $input.item.json;
const results = data.data?.results || [];
const currentPage = data.data?.pagination?.currentPage || 0;
const totalPages = data.data?.pagination?.totalPages || 0;
const totalItems = data.data?.pagination?.totalItems || 0;

const cruzeiros = [];

for (const result of results) {
  const departure = result.departureOptions?.[0] || {};
  const cruiseLine = departure.cruiseLine || {};
  const ship = departure.ship || {};
  const fares = departure.fares || [];
  const benefits = departure.sailingBenefits || [];

  // Montar preços por tipo de cabine
  const precos = {};
  for (const fare of fares) {
    if (fare.totalAmount > 0) {
      precos[fare.type] = {
        valorTotal: fare.totalAmount,
        valorCabine: fare.cabinAmountWithNCF,
        categoria: fare.categoryCode,
        maisBarato: fare.isCheapest
      };
    }
  }

  // Formatar data (ex: 20270329 -> 29/03/2027)
  const dateRaw = String(departure.date || '');
  const dataFormatada = dateRaw.length === 8
    ? `${dateRaw.slice(6,8)}/${dateRaw.slice(4,6)}/${dateRaw.slice(0,4)}`
    : dateRaw;

  // Benefícios como lista simples
  const beneficiosList = benefits.map(b => b.name).join(', ');

  cruzeiros.push({
    json: {
      // Identificação
      codigoViagem: result.sailingCode,
      codigoItinerario: result.itinerary?.itineraryCode,
      pagina: currentPage,
      totalPaginas: totalPages,
      totalItinerarios: totalItems,

      // Rota
      embarque: result.departure?.name,
      codigoEmbarque: result.departure?.code,
      desembarque: result.arrive?.name,
      codigoDesembarque: result.arrive?.code,

      // Destino e itinerário
      destino: result.itinerary?.destination,
      itinerario: result.itinerary?.name,

      // Companhia e navio
      companhiaCruzeiro: cruiseLine.name,
      codigoCompanhia: cruiseLine.code,
      navio: ship.name,
      codigoNavio: ship.code,

      // Datas
      dataPartida: dataFormatada,
      noites: departure.nights,

      // Preços
      melhorPrecoTotal: result.bestTotalAmount,
      melhorPrecoCabine: result.bestCabinAmountWithNCF,
      precosCabine: JSON.stringify(precos),

      // Extras
      beneficios: beneficiosList,
      vooDisponivel: result.flightsAvailable,
      pacotePrePos: result.prePostPackageAvailable,
      reservaOnline: cruiseLine.onlineBooking
    }
  });
}

return cruzeiros;

// Consolidar todos os cruzeiros em um único array
const todosOsItems = $input.all();
const todosCruzeiros = [];

for (const item of todosOsItems) {
  const cruzeiros = item.json.cruzeiros || [];
  for (const c of cruzeiros) {
    todosCruzeiros.push(c);
  }
}

// Ordenar por data de partida
todosCruzeiros.sort((a, b) => {
  const dateA = a.dataPartida?.split('/').reverse().join('') || '';
  const dateB = b.dataPartida?.split('/').reverse().join('') || '';
  return dateA.localeCompare(dateB);
});

// Remover duplicatas pelo código da viagem
const vistos = new Set();
const semDuplicatas = todosCruzeiros.filter(c => {
  if (vistos.has(c.codigoViagem)) return false;
  vistos.add(c.codigoViagem);
  return true;
});

return [{
  json: {
    totalColetados: semDuplicatas.length,
    dataExtracao: new Date().toLocaleString('pt-BR'),
    cruzeiros: semDuplicatas
  }
}];

// Converter para linhas individuais para exportação em planilha
const data = $input.item.json;
const cruzeiros = data.cruzeiros || [];

return cruzeiros.map(c => ({ json: c }));
